function maxArea(h, w, horizontalCuts, verticalCuts) {
    horizontalCuts.sort((a, b) => a - b);
    verticalCuts.sort((a, b) => a - b);

    let maxH = Math.max(horizontalCuts[0], h - horizontalCuts[horizontalCuts.length - 1]);
    let maxV = Math.max(verticalCuts[0], w - verticalCuts[verticalCuts.length - 1]);

    for (let i = 1; i < horizontalCuts.length; ++i) {
        maxH = Math.max(maxH, horizontalCuts[i] - horizontalCuts[i - 1]);
    }

    for (let i = 1; i < verticalCuts.length; ++i) {
        maxV = Math.max(maxV, verticalCuts[i] - verticalCuts[i - 1]);
    }

    return BigInt(maxH) * BigInt(maxV) % 1000000007n;
}
```

    1. Sort both horizontalCuts and verticalCuts arrays in ascending order.
2. Calculate the initial values of maxH and maxV as the maximum of the first cut distance and the distance from the last cut to the cake's edge.
3. Loop through each cut in both arrays (starting from index 1), updating maxH and maxV to be the maximum value between their current value and the difference between the current cut and the previous cut. This will give us the largest distance between cuts for both horizontal and vertical directions.
4. Return the product of maxH and maxV modulo 10^9 + 7.

